// Mirrors the frozen screenplay IR contract in docs/screenplay-format.md.
// The renderer consumes an already-validated screenplay; zod validation of
// LLM output happens upstream at the screenwriter boundary, not here.

export type Emotion =
  | "neutral"
  | "confident"
  | "confused"
  | "panicking"
  | "smug"
  | "defeated"
  | "celebrating";

// ToolEvent is sketched but not pinned down in the contract doc; this is the
// minimal shape the classic pack needs. Extend the doc before extending this.
export type ToolEvent = {
  tool: string; // "Read", "Grep", "Bash", "Edit", ...
  detail: string; // "auth.ts", `"session token"`, "npm test → exit 1"
  status?: "ok" | "fail";
};

export type DiffLine = {
  kind: "context" | "removed" | "added";
  text: string;
};

// TODO: the contract allows Diff | TestRun | Screenshot artifacts; only Diff
// is implemented in this bare v0 renderer.
export type Diff = {
  file: string;
  lines: DiffLine[];
};

export type TitleScene = {
  type: "title";
  task: string;
};

export type DialogueScene = {
  type: "dialogue";
  lines: Array<{
    speaker: "user" | "claude";
    text: string; // condensed, <= 90 chars
    emotion: Emotion;
  }>;
};

export type ActionScene = {
  type: "action";
  events: ToolEvent[];
  intensity: "montage" | "steady";
};

export type ShowcaseScene = {
  type: "showcase";
  artifact: Diff;
  verdict: "fail" | "pass" | "reveal";
};

export type StatsScene = {
  type: "stats";
  compressed: { realDuration: string; movieDuration: string };
  counts: { files: number; added: number; removed: number; tools: number };
  achievements: Array<{ title: string }>;
  grade?: string;
};

export type Scene = (
  | TitleScene
  | DialogueScene
  | ActionScene
  | ShowcaseScene
  | StatsScene
) & {
  targetSec: number;
  caption?: string;
};

export type Screenplay = {
  version: 1;
  sessionMeta: { repo?: string; startedAt?: string };
  targetDurationSec: number; // 45–60
  scenes: Scene[];
};

import type { Screenplay } from "./types";

// NOTE: the task spec names fixtures/screenplays/sample.json as the frozen
// input, but that file does not exist in the repo yet (main is docs-only).
// This is a stand-in that conforms to docs/screenplay-format.md; swap it for
// an import of the real fixture when it lands.
export const sampleScreenplay: Screenplay = {
  version: 1,
  sessionMeta: { repo: "acme/checkout", startedAt: "2026-06-30T14:02:00Z" },
  targetDurationSec: 45,
  scenes: [
    {
      type: "title",
      task: "fix the flaky session-token test before the demo",
      targetSec: 6,
      caption: "one test. two hours. no pressure.",
    },
    {
      type: "action",
      intensity: "montage",
      targetSec: 12,
      caption: "turn 3 — reading everything that has ever mentioned a token",
      events: [
        { tool: "Read", detail: "auth.ts" },
        { tool: "Grep", detail: '"session token"' },
        { tool: "Read", detail: "session.ts" },
        { tool: "Bash", detail: "npm test → exit 1", status: "fail" },
        { tool: "Read", detail: "token-cache.ts" },
        { tool: "Grep", detail: '"expiresAt"' },
        { tool: "Read", detail: "clock.ts" },
        { tool: "Edit", detail: "session.ts" },
        { tool: "Bash", detail: "npm test → exit 1", status: "fail" },
        { tool: "Read", detail: "test/session.test.ts" },
        { tool: "Grep", detail: '"Date.now"' },
        { tool: "Read", detail: "fake-timers.ts" },
        { tool: "Edit", detail: "token-cache.ts" },
        { tool: "Bash", detail: "npm test → ok", status: "ok" },
      ],
    },
    {
      type: "showcase",
      verdict: "pass",
      targetSec: 15,
      caption: "turn 23 — the cache trusted the wall clock",
      artifact: {
        file: "src/token-cache.ts",
        lines: [
          { kind: "context", text: "export function isFresh(token: CachedToken): boolean {" },
          { kind: "removed", text: "  // expiry checked against real time — flaky under fake timers" },
          { kind: "removed", text: "  return token.expiresAt > Date.now();" },
          { kind: "added", text: "  // expiry checked against the injected clock, testable" },
          { kind: "added", text: "  return token.expiresAt > clock.now();" },
          { kind: "added", text: "  // clock defaults to system time in production" },
          { kind: "context", text: "}" },
        ],
      },
    },
    {
      type: "stats",
      targetSec: 12,
      caption: "made with sessionmovie",
      compressed: { realDuration: "2h 14m", movieDuration: "45s" },
      counts: { files: 7, added: 412, removed: 118, tools: 63 },
      achievements: [
        { title: "Archaeologist" },
        { title: "Rage Quit Averted" },
      ],
      grade: "B+",
