11	import { Caption } from "./Caption";
12	
13	const toolColor = (event: ToolEvent): string => {
14	  if (event.status === "fail") return theme.red;
15	  if (event.status === "ok") return theme.green;
16	  switch (event.tool) {
17	    case "Read":
18	      return theme.blue;
19	    case "Grep":
20	      return theme.purple;
21	    case "Edit":
22	      return theme.yellow;
23	    default:
24	      return theme.text;
25	  }
26	};
27	
28	const CHIP_GAP = 150;
29	
30	export const Action: React.FC<{
31	  scene: ActionScene;
32	  caption?: string;
33	  durationInFrames: number;
34	}> = ({ scene, caption, durationInFrames }) => {
35	  const frame = useCurrentFrame();
36	  const { height, fps } = useVideoConfig();
37	
38	  // Chips stream in over the first ~80% of the scene; montage packs them tighter.
39	  const streamFrames = durationInFrames * (scene.intensity === "montage" ? 0.75 : 0.9);
40	  const interval = Math.max(4, (streamFrames - 10) / scene.events.length);
41	
42	  const slideDur = Math.min(12, interval);
43	  const chipProgress = (i: number) =>
44	    interpolate(frame, [10 + i * interval, 10 + i * interval + slideDur], [0, 1], {
45	      easing: Easing.bezier(0.16, 1, 0.3, 1),
46	      extrapolateLeft: "clamp",
47	      extrapolateRight: "clamp",
48	    });
49	
50	  // Every chip that lands pushes the whole stack up by one slot.
51	  const scrollUp = scene.events.reduce((acc, _e, i) => acc + chipProgress(i), 0);
52	  const baselineY = height * 0.62;
53	
54	  const captionIn = interpolate(frame, [8, 25], [0, 1], {
55	    extrapolateLeft: "clamp",
56	    extrapolateRight: "clamp",
57	  });
58	
59	  return (
60	    <AbsoluteFill
61	      style={{ backgroundColor: theme.bg, fontFamily: theme.mono, overflow: "hidden" }}
62	    >
63	      {scene.events.map((event, i) => {
64	        const p = chipProgress(i);
65	        if (p === 0) return null;
66	        const y = baselineY + i * CHIP_GAP - scrollUp * CHIP_GAP;
67	        // Fade chips out as they ride off the top.
68	        const fadeOut = interpolate(y, [120, height * 0.28], [0, 1], {
69	          extrapolateLeft: "clamp",
